#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;scanf("%d %d",&n,&m);vector<long long>a(n),b(m);for(auto&x:a)scanf("%lld",&x);for(auto&x:b)scanf("%lld",&x);int i=0,j=0;string out;while(i<n||j<m){if(j>=m||(i<n&&a[i]<=b[j]))out+=to_string(a[i++]);else out+=to_string(b[j++]);out+=' ';}if(!out.empty())out.back()='\n';fputs(out.c_str(),stdout);}
